function maxProduct(nums) {
    let maxProd = nums[0];
    let minProd = nums[0];
    let ans = nums[0];

    for (let i = 1; i < nums.length; i++) {
        if (nums[i] < 0) {
            [maxProd, minProd] = [minProd, maxProd];
        }

        maxProd = Math.max(nums[i], maxProd * nums[i]);
        minProd = Math.min(nums[i], minProd * nums[i]);

        ans = Math.max(ans, maxProd);
    }

    return ans;
}
